// checkGuess returns an array of 5 status strings for each letter:
// 'correct' = right letter, right position (green)
// 'present' = right letter, wrong position (yellow)
// 'absent'  = letter not in word (gray)
//
// Handles duplicate letters correctly using a two-pass approach:
// Pass 1: mark exact matches, consuming those target slots
// Pass 2: mark present-but-wrong-position, consuming remaining target slots

function checkGuess(guess, target) {
  const result = new Array(5).fill('absent');
  const targetArr = [...target];
  const guessArr  = [...guess];

  // Pass 1 — exact matches
  for (let i = 0; i < 5; i++) {
    if (guessArr[i] === targetArr[i]) {
      result[i]    = 'correct';
      targetArr[i] = null;   // consume this target slot
      guessArr[i]  = null;   // skip in pass 2
    }
  }

  // Pass 2 — present but wrong position
  for (let i = 0; i < 5; i++) {
    if (guessArr[i] === null) continue;
    const j = targetArr.indexOf(guessArr[i]);
    if (j !== -1) {
      result[i]    = 'present';
      targetArr[j] = null;   // consume to avoid double-counting
    }
  }

  return result;
}
