    guesses.push(input);
    results.push(result);
    updateLetterStatus(letterStatus, input, result);

    if (result.every(r => r === 'correct')) {
      won = true;
    }
  }

  // Final screen
  clear();
  renderTitle();
  renderBoard(guesses, results);
  renderKeyboard(letterStatus);

  if (won) {
    const msgs   = ['Genius!', 'Magnificent!', 'Impressive!', 'Splendid!', 'Great!', 'Phew!'];
