    console.log('\n\n  Goodbye!\n');
    rl.close();
    process.exit(0);
  });

  let keep = true;
  while (keep) {
    keep = await playGame(rl);
  }

  clear();
  console.log('\n  Thanks for playing Wordle! Goodbye.\n');
  rl.close();
}

