function renderTitle() {
  console.log(`\n${BOLD}  ╔══════════════════╗`);
  console.log(`  ║   W O R D L E    ║`);
  console.log(`  ╚══════════════════╝${RESET}\n`);
}

function renderBoard(guesses, results) {
  for (let row = 0; row < MAX_GUESSES; row++) {
    process.stdout.write('  ');
    if (row < guesses.length) {
      const guess  = guesses[row];
      const result = results[row];
      for (let col = 0; col < WORD_LEN; col++) {
        process.stdout.write(colorize(guess[col], result[col]));
      }
    } else {
      for (let col = 0; col < WORD_LEN; col++) {
        process.stdout.write(`${GRAY}   ${RESET}`);
      }
    }
    console.log();
  }
  console.log();
}

function renderKeyboard(letterStatus) {
  for (const row of KEYBOARD_ROWS) {
    process.stdout.write('  ');
    for (const letter of row) {
      const status = letterStatus[letter];
      if (status === 'correct') {
        process.stdout.write(`${GREEN}${letter.toUpperCase()}${RESET}`);
      } else if (status === 'present') {
        process.stdout.write(`${YELLOW}${letter.toUpperCase()}${RESET}`);
      } else if (status === 'absent') {
        process.stdout.write(`${GRAY}${letter}${RESET}`);
      } else {
        process.stdout.write(`${DIM}${letter}${RESET}`);
      }
      process.stdout.write(' ');
    }
    console.log();
  }
  console.log();
}

// Merge new result into letter status (correct > present > absent)
function updateLetterStatus(letterStatus, guess, result) {
  const priority = { correct: 3, present: 2, absent: 1 };
  for (let i = 0; i < WORD_LEN; i++) {
    const letter = guess[i];
    const prev   = letterStatus[letter];
    if (!prev || priority[result[i]] > priority[prev]) {
      letterStatus[letter] = result[i];
    }
  }
}

// ─── Main game loop ───────────────────────────────────────────────────────────
async function playGame(rl) {
  const target       = pickWord();
  const guesses      = [];
  const results      = [];
  const letterStatus = {};
  let won            = false;

  const ask = (prompt) => new Promise(resolve => {
    rl.question(prompt, answer => resolve(answer.trim().toLowerCase()));
  });

  while (guesses.length < MAX_GUESSES && !won) {
    clear();
    renderTitle();
    renderBoard(guesses, results);
    renderKeyboard(letterStatus);

    const attemptsLeft = MAX_GUESSES - guesses.length;
    process.stdout.write(`  Guess (${attemptsLeft} left): `);
    const input = await ask('');

    if (input.length !== WORD_LEN || !/^[a-z]+$/.test(input)) {
      clear();
      renderTitle();
      renderBoard(guesses, results);
      renderKeyboard(letterStatus);
      console.log(`  ${YELLOW} ! ${RESET} Enter a 5-letter word.\n`);
      await ask('  Press Enter to continue...');
      continue;
    }

    const result = checkGuess(input, target);
    guesses.push(input);
    results.push(result);
    updateLetterStatus(letterStatus, input, result);

    if (result.every(r => r === 'correct')) {
      won = true;
    }
  }

  // Final screen
  clear();
  renderTitle();
  renderBoard(guesses, results);
  renderKeyboard(letterStatus);

  if (won) {
    const msgs   = ['Genius!', 'Magnificent!', 'Impressive!', 'Splendid!', 'Great!', 'Phew!'];
    const msg    = msgs[Math.min(guesses.length - 1, msgs.length - 1)];
    const streak = guesses.length;
    console.log(`  ${GREEN} ${msg} ${RESET}  Solved in ${BOLD}${streak}${RESET} guess${streak > 1 ? 'es' : ''}!\n`);
  } else {
    console.log(`  ${GRAY} Game over! ${RESET}  The word was ${BOLD}${target.toUpperCase()}${RESET}\n`);
  }

  const again = await ask('  Play again? (y/n): ');
  return again === 'y' || again === 'yes';
}

async function main() {
  const rl = readline.createInterface({
    input:  process.stdin,
    output: process.stdout,
  });

  // Hide typed input echoing during board display
  rl.on('SIGINT', () => {
    console.log('\n\n  Goodbye!\n');
    rl.close();
    process.exit(0);
  });

  let keep = true;
  while (keep) {
    keep = await playGame(rl);
  }

  clear();
  console.log('\n  Thanks for playing Wordle! Goodbye.\n');
  rl.close();
}

main();

